// Logout is the resolver for the logout field.
func (r *mutationResolver) Logout(ctx context.Context, refreshToken *string) (*GeneralResponse, error) {
	logger := middleware.GetLogger()

	// 1. 获取当前JWT token（从请求头）
	if ginCtx, ok := ctx.(*gin.Context); ok {
		authHeader := ginCtx.GetHeader("Authorization")
		if authHeader != "" && strings.HasPrefix(authHeader, "Bearer ") {
			tokenString := strings.TrimPrefix(authHeader, "Bearer ")

			// 将JWT token添加到黑名单
			blacklist := models.GetTokenBlacklist()
			if err := blacklist.AddToBlacklist(tokenString, "logout"); err != nil {
				logger.Warnw("Failed to blacklist JWT token", "error", err)
			} else {
				logger.Infow("JWT token blacklisted", "token_prefix", tokenString[:min(10, len(tokenString))])
			}
		}
	}

	// 2. 如果提供了 refresh token，撤销它
	if refreshToken != nil && *refreshToken != "" {
		rt, err := models.VerifyRefreshToken(*refreshToken, r.Resolver.DB)
		if err != nil {
			// refresh token 无效或已过期，记录但不影响登出
			logger.Warnw("Invalid refresh token during logout", "error", err)
		} else {
			// 撤销 refresh token
			if err := rt.Revoke(r.Resolver.DB); err != nil {
				logger.Warnw("Failed to revoke refresh token", "error", err)
			} else {
				logger.Infow("Refresh token revoked", "user_id", rt.UserID)
			}
		}
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr("成功退出登录"),
		Code:    strPtr("SUCCESS"),
	}, nil
}

// RefreshToken is the resolver for the refreshToken field.
func (r *mutationResolver) RefreshToken(ctx context.Context, refreshToken string) (*AuthPayload, error) {
	logger := middleware.GetLogger()

	// 1. 验证 refresh token
	rt, err := models.VerifyRefreshToken(refreshToken, r.Resolver.DB)
	if err != nil {
		logger.Errorw("Refresh token validation failed", "error", err)
		return nil, fmt.Errorf("无效或过期的refresh token: %w", err)
	}

	// 2. 获取关联的用户
	var user models.User
	if err := r.Resolver.DB.First(&user, rt.UserID).Error; err != nil {
		logger.Errorw("User not found for refresh token", "user_id", rt.UserID, "error", err)
		return nil, fmt.Errorf("用户不存在")
	}

	// 3. 检查用户状态
	if !user.IsActive {
		return nil, fmt.Errorf("用户账户已被禁用")
	}

	// 4. 生成新的 JWT access token
	token, err := models.GenerateJWT(user.ID, user.Username, user.Role, false)
	if err != nil {
		logger.Errorw("Failed to generate new JWT", "error", err)
		return nil, fmt.Errorf("生成token失败")
	}

	// 5. 生成新的 refresh token（旋转策略）
	newRefreshToken, _, err := models.GenerateRefreshToken(user.ID, models.DefaultRefreshTokenConfig, r.Resolver.DB)
	if err != nil {
		logger.Errorw("Failed to generate new refresh token", "error", err)
		// 即使新refresh token生成失败，仍然返回access token
		// 使用旧的refresh token
		newRefreshToken = refreshToken
	} else {
		// 6. 撤销旧的 refresh token（旋转策略）
		if err := rt.Revoke(r.Resolver.DB); err != nil {
			logger.Warnw("Failed to revoke old refresh token", "error", err)
			// 不影响主流程，只记录警告
		}
	}

	expiresAt := time.Now().Add(24 * time.Hour)
	logger.Infow("Token refreshed successfully", "user_id", user.ID)

	return &AuthPayload{
		Token:        token,
		RefreshToken: newRefreshToken,
		User:         convertToGraphQLUser(&user),
		ExpiresAt:    expiresAt,
	}, nil
}

// SendVerificationCode is the resolver for the sendVerificationCode field.
func (r *mutationResolver) SendVerificationCode(ctx context.Context, email string, typeArg VerificationType) (*GeneralResponse, error) {
	// 验证邮箱格式
	if email == "" {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("邮箱地址不能为空"),
			Code:    strPtr("EMAIL_REQUIRED"),
		}, nil
	}

	// 根据验证类型检查用户是否存在
	var user models.User
	err := r.Resolver.DB.Where("email = ?", email).First(&user).Error

	if typeArg == VerificationTypeRegister {
		// 注册验证：邮箱不应该存在
		if err == nil {
			return &GeneralResponse{
				Success: false,
				Message: strPtr("该邮箱已被注册"),
				Code:    strPtr("EMAIL_EXISTS"),
			}, nil
		}
	} else {
		// 登录或重置密码：邮箱必须存在
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return &GeneralResponse{
				Success: false,
				Message: strPtr("用户不存在"),
				Code:    strPtr("USER_NOT_FOUND"),
			}, nil
		}
		if err != nil {
			return nil, fmt.Errorf("数据库查询失败: %w", err)
		}
	}

	// 调用统一认证服务发送验证码（内部处理生成与存储）
	authService := services.NewAuthService(r.Resolver.DB)
	if err := authService.SendVerificationCode(email, string(typeArg)); err != nil {
		return &GeneralResponse{
			Success: false,
			Message: strPtr(err.Error()),
			Code:    strPtr("EMAIL_SEND_FAILED"),
		}, nil
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr("验证码已发送到您的邮箱"),
		Code:    strPtr("VERIFICATION_CODE_SENT"),
	}, nil
}

// VerifyEmail is the resolver for the verifyEmail field.
func (r *mutationResolver) VerifyEmail(ctx context.Context, input VerifyEmailInput) (*GeneralResponse, error) {
	// 验证输入参数
	if input.Email == "" {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("邮箱地址不能为空"),
			Code:    strPtr("EMAIL_REQUIRED"),
		}, nil
	}

	if len(input.Code) < 4 {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("验证码格式错误"),
			Code:    strPtr("INVALID_CODE"),
		}, nil
	}

	// 验证验证码（按类型）
	if !verifyCode(input.Email, input.Code, string(input.Type)) {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("验证码错误或已过期"),
			Code:    strPtr("INVALID_OR_EXPIRED_CODE"),
		}, nil
	}

	// 查找用户
	var user models.User
	if err := r.Resolver.DB.Where("email = ?", input.Email).First(&user).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			// 验证成功但用户不存在，删除验证码
			deleteVerificationCode(input.Email, string(input.Type))
			return &GeneralResponse{
				Success: false,
				Message: strPtr("用户不存在"),
				Code:    strPtr("USER_NOT_FOUND"),
			}, nil
		}
		return nil, fmt.Errorf("数据库查询失败: %w", err)
	}

	// 根据验证类型执行相应操作
	switch input.Type {
	case VerificationTypeRegister, VerificationTypeLogin:
		// 注册或登录验证：标记邮箱为已验证
		if !user.IsVerified {
			now := time.Now()
			user.IsVerified = true
			user.EmailVerifiedAt = &now
			if err := r.Resolver.DB.Save(&user).Error; err != nil {
				return nil, fmt.Errorf("更新用户验证状态失败: %w", err)
			}
		}
	case VerificationTypeResetPassword:
		// 密码重置验证：验证成功即可，不需要更新用户状态
		// 实际的密码重置在 confirmPasswordReset 中处理
	}

	// 验证成功，删除验证码
	deleteVerificationCode(input.Email, string(input.Type))

	return &GeneralResponse{
		Success: true,
		Message: strPtr("邮箱验证成功"),
		Code:    strPtr("EMAIL_VERIFIED"),
	}, nil
}

