// AdminCreateUser is the resolver for the adminCreateUser field.
func (r *mutationResolver) AdminCreateUser(ctx context.Context, input AdminCreateUserInput) (*User, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 检查用户名是否已存在
	var existingUser models.User
	if err := r.DB.Where("username = ?", input.Username).First(&existingUser).Error; err == nil {
		return nil, ErrUserExists
	}

	// 检查邮箱是否已存在
	if err := r.DB.Where("email = ?", input.Email).First(&existingUser).Error; err == nil {
		return nil, GraphQLError{Message: "邮箱已被使用", Code: "EMAIL_EXISTS"}
	}

	// 创建新用户
	role := "user" // 默认角色
	if input.Role != nil {
		role = string(*input.Role)
	}

	user := models.User{
		Username:   input.Username,
		Email:      input.Email,
		Password:   input.Password, // 应该在模型中自动哈希
		Role:       role,
		IsVerified: *input.IsVerified,
		IsActive:   true,
	}

	if err := r.DB.Create(&user).Error; err != nil {
		return nil, fmt.Errorf("创建用户失败: %w", err)
	}

	return convertToGraphQLUser(&user), nil
}

// AdminUpdateUser is the resolver for the adminUpdateUser field.
func (r *mutationResolver) AdminUpdateUser(ctx context.Context, id string, username *string, email *string, role *UserRole, isVerified *bool, isActive *bool) (*User, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 解析用户ID
	userID, err := parseID(id)
	if err != nil {
		return nil, err
	}

	// 查找用户
	var user models.User
	if err := r.DB.First(&user, userID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrUserNotFound
		}
		return nil, fmt.Errorf("查询用户失败: %w", err)
	}

	// 更新字段
	if username != nil {
		// 检查用户名是否已被其他用户使用
		var existingUser models.User
		if err := r.DB.Where("username = ? AND id != ?", *username, userID).First(&existingUser).Error; err == nil {
			return nil, GraphQLError{Message: "用户名已被使用", Code: "USERNAME_EXISTS"}
		}
		user.Username = *username
	}

	if email != nil {
		// 检查邮箱是否已被其他用户使用
		var existingUser models.User
		if err := r.DB.Where("email = ? AND id != ?", *email, userID).First(&existingUser).Error; err == nil {
			return nil, GraphQLError{Message: "邮箱已被使用", Code: "EMAIL_EXISTS"}
		}
		user.Email = *email
	}

	logger := middleware.GetLogger()

	if role != nil {
		logger.Infow("更新用户角色", "userId", userID, "oldRole", user.Role, "newRole", string(*role))
		user.Role = string(*role)
	}

	if isVerified != nil {
		user.IsVerified = *isVerified
	}

	if isActive != nil {
		user.IsActive = *isActive
	}

	// 保存更新
	if err := r.DB.Save(&user).Error; err != nil {
		logger.Errorw("更新用户失败", "userId", userID, "error", err)
		return nil, fmt.Errorf("更新用户失败: %w", err)
	}

	logger.Infow("用户更新成功", "userId", userID, "username", user.Username, "role", user.Role)

	return convertToGraphQLUser(&user), nil
}

// AdminDeleteUser is the resolver for the adminDeleteUser field.
func (r *mutationResolver) AdminDeleteUser(ctx context.Context, id string) (*GeneralResponse, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 解析用户ID
	userID, err := parseID(id)
	if err != nil {
		return nil, err
	}

	// 查找用户
	var user models.User
	if err := r.DB.First(&user, userID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return nil, ErrUserNotFound
		}
		return nil, fmt.Errorf("查询用户失败: %w", err)
	}

	// 不能删除管理员账户（安全限制）
	if user.Role == "ADMIN" {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("不能删除管理员账户"),
			Code:    strPtr("CANNOT_DELETE_ADMIN"),
		}, nil
	}

	// 开始事务，同时删除用户相关数据
	tx := r.DB.Begin()
	defer func() {
		if r := recover(); r != nil {
			tx.Rollback()
		}
	}()

	// 删除用户的文章（软删除）
	if err := tx.Where("author_id = ?", userID).Delete(&models.BlogPost{}).Error; err != nil {
		tx.Rollback()
		return nil, fmt.Errorf("删除用户文章失败: %w", err)
	}

	// 删除用户的评论
	if err := tx.Where("user_id = ?", userID).Delete(&models.BlogPostComment{}).Error; err != nil {
		tx.Rollback()
		return nil, fmt.Errorf("删除用户评论失败: %w", err)
	}

	// 删除用户账户
	if err := tx.Delete(&user).Error; err != nil {
		tx.Rollback()
		return nil, fmt.Errorf("删除用户失败: %w", err)
	}

	if err := tx.Commit().Error; err != nil {
		return nil, fmt.Errorf("提交删除用户事务失败: %w", err)
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr("用户删除成功"),
		Code:    strPtr("DELETE_SUCCESS"),
	}, nil
}

// CreateInviteCode is the resolver for the createInviteCode field.
func (r *mutationResolver) CreateInviteCode(ctx context.Context, input CreateInviteCodeInput) (*InviteCode, error) {
	// 验证管理员权限
	currentUser, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 生成唯一的邀请码
	code := models.GenerateInviteCode()

	// 验证邀请码唯一性
	var existingCode models.InviteCode
	if err := r.DB.Where("code = ?", code).First(&existingCode).Error; err == nil {
		// 如果存在重复，重新生成
		code = models.GenerateInviteCode()
	}

	// 设置默认值
	maxUses := 1
	if input.MaxUses != nil {
		maxUses = *input.MaxUses
	}

	// 创建邀请码
	inviteCode := models.InviteCode{
		Code:        code,
		CreatedByID: currentUser.ID,
		MaxUses:     maxUses,
		CurrentUses: 0,
		IsActive:    true,
	}

	// 处理可选字段
	if input.Description != nil {
		inviteCode.Description = *input.Description
	}

	if !input.ExpiresAt.IsZero() {
		inviteCode.ExpiresAt = &input.ExpiresAt
	}

	// 保存到数据库
	if err := r.DB.Create(&inviteCode).Error; err != nil {
		return nil, fmt.Errorf("创建邀请码失败: %w", err)
	}

	// 预加载关联数据
	if err := r.DB.Preload("CreatedBy").First(&inviteCode, inviteCode.ID).Error; err != nil {
		return nil, fmt.Errorf("获取邀请码详情失败: %w", err)
	}

	// 转换为GraphQL类型
	var description *string
	if inviteCode.Description != "" {
		description = &inviteCode.Description
	}

	var expiresAt time.Time
	if inviteCode.ExpiresAt != nil {
		expiresAt = *inviteCode.ExpiresAt
	} else {
		// 如果没有过期时间，返回一个很远的未来时间表示"永不过期"
		expiresAt = time.Date(2999, 12, 31, 23, 59, 59, 0, time.UTC)
	}

	return &InviteCode{
		ID:          strconv.FormatUint(uint64(inviteCode.ID), 10),
		Code:        inviteCode.Code,
		CreatedBy:   convertToGraphQLUser(&inviteCode.CreatedBy),
		UsedBy:      nil, // 新创建的邀请码未被使用
		UsedAt:      nil,
		ExpiresAt:   expiresAt,
		MaxUses:     inviteCode.MaxUses,
		CurrentUses: inviteCode.CurrentUses,
		IsActive:    inviteCode.IsActive,
		Description: description,
		CreatedAt:   inviteCode.CreatedAt,
	}, nil
}

// DeactivateInviteCode is the resolver for the deactivateInviteCode field.
func (r *mutationResolver) DeactivateInviteCode(ctx context.Context, id string) (*GeneralResponse, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 解析邀请码ID
	inviteCodeID, err := parseID(id)
	if err != nil {
		return nil, err
	}

	// 查找邀请码
	var inviteCode models.InviteCode
	if err := r.DB.First(&inviteCode, inviteCodeID).Error; err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return &GeneralResponse{
				Success: false,
				Message: strPtr("邀请码不存在"),
				Code:    strPtr("INVITE_CODE_NOT_FOUND"),
			}, nil
		}
		return nil, fmt.Errorf("查询邀请码失败: %w", err)
	}

	// 检查邀请码是否已经被停用
	if !inviteCode.IsActive {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("邀请码已经被停用"),
			Code:    strPtr("INVITE_CODE_ALREADY_INACTIVE"),
		}, nil
	}

	// 停用邀请码
	if err := r.DB.Model(&inviteCode).Update("is_active", false).Error; err != nil {
		return nil, fmt.Errorf("停用邀请码失败: %w", err)
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr("邀请码已成功停用"),
		Code:    strPtr("DEACTIVATE_SUCCESS"),
	}, nil
}

// ClearCache is the resolver for the clearCache field.
func (r *mutationResolver) ClearCache(ctx context.Context) (*GeneralResponse, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	// 统计清理的缓存数量
	var clearedCount int

	// 1. 清理全局缓存
	globalCache := models.GetCache()
	if globalCache != nil {
		clearedCount += globalCache.Count()
		globalCache.Clear()
	}

	// 2. 清理搜索缓存
	searchCache := services.GetGlobalSearchCache()
	if searchCache != nil {
		clearedCount += searchCache.GetCacheStats()["total_items"].(int)
		searchCache.InvalidateAll()
	}

	// 3. 清理邮箱验证缓存（过期的验证码）
	emailVerificationSvc := models.GetEmailVerificationService()
	if emailVerificationSvc != nil {
		// 只能清理过期的，无法访问未导出的 cache 字段
		// 这个服务会自动清理过期的验证码
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr(fmt.Sprintf("缓存清理成功，共清理 %d 项缓存", clearedCount)),
		Code:    strPtr("CACHE_CLEARED"),
	}, nil
}

// RebuildSearchIndex is the resolver for the rebuildSearchIndex field.
func (r *mutationResolver) RebuildSearchIndex(ctx context.Context) (*GeneralResponse, error) {
	// 验证管理员权限
	_, err := requireAdmin(ctx, r.DB)
	if err != nil {
		return nil, err
	}

	logger := middleware.GetLogger()
	logger.Infow("开始重建搜索索引")

	// 1. 清空 FTS 表
	if err := r.DB.Exec("DELETE FROM blog_post_fts").Error; err != nil {
		logger.Errorw("清空FTS表失败", "error", err)
		// 如果表不存在，继续执行
	}

	// 2. 获取所有已发布的文章
	var posts []models.BlogPost
	if err := r.DB.Where("status = ?", "PUBLISHED").Find(&posts).Error; err != nil {
		return &GeneralResponse{
			Success: false,
			Message: strPtr(fmt.Sprintf("获取文章失败: %v", err)),
			Code:    strPtr("REBUILD_INDEX_FAILED"),
		}, nil
	}

	// 3. 重新索引所有文章到FTS表
	successCount := 0
	for _, post := range posts {
		insertSQL := `INSERT INTO blog_post_fts(rowid, title, content, tags, categories)
			VALUES (?, ?, ?, ?, ?)`

		if err := r.DB.Exec(insertSQL, post.ID, post.Title, post.Content, post.Tags, post.Categories).Error; err != nil {
			logger.Errorw("索引文章失败", "post_id", post.ID, "error", err)
			continue
		}
		successCount++
	}

	// 4. 清空搜索缓存
	searchCache := services.GetGlobalSearchCache()
	if searchCache != nil {
		searchCache.InvalidateAll()
	}

	logger.Infow("搜索索引重建完成", "total", len(posts), "success", successCount)

	return &GeneralResponse{
		Success: true,
		Message: strPtr(fmt.Sprintf("搜索索引重建完成，共索引 %d/%d 篇文章", successCount, len(posts))),
		Code:    strPtr("INDEX_REBUILT"),
	}, nil
}

// SyncNotion is the resolver for the syncNotion field.
// SyncNotion is the resolver for the syncNotion field.
// SyncNotion is the resolver for the syncNotion field.
func (r *mutationResolver) SyncNotion(ctx context.Context, pageID *string) (*GeneralResponse, error) {
	// 获取当前用户（需管理员权限）
	user, err := requireAdmin(ctx, r.Resolver.DB)
	if err != nil {
		return nil, fmt.Errorf("未授权访问: %w", err)
	}

	if r.Resolver.NotionService == nil {
		return &GeneralResponse{
			Success: false,
			Message: strPtr("Notion服务未初始化，请检查是否配置了 NOTION_API_KEY"),
			Code:    strPtr("NOTION_SERVICE_NOT_INIT"),
		}, nil
	}

	targetPageID := ""
	if pageID != nil {
		targetPageID = *pageID
	}

	// 执行同步
	if err := r.Resolver.NotionService.SyncPosts(ctx, user, targetPageID); err != nil {
		return &GeneralResponse{
			Success: false,
			Message: strPtr(fmt.Sprintf("同步失败: %v", err)),
			Code:    strPtr("SYNC_FAILED"),
		}, nil
	}

	successMsg := "Notion文章同步成功"
	if targetPageID != "" {
		successMsg = fmt.Sprintf("Notion页面 %s 同步成功", targetPageID)
	}

	return &GeneralResponse{
		Success: true,
		Message: strPtr(successMsg),
		Code:    strPtr("SUCCESS"),
	}, nil
}

// UpdateGitHubConfig is the resolver for the updateGitHubConfig field.
func (r *mutationResolver) UpdateGitHubConfig(ctx context.Context, repo string, token string) (*GeneralResponse, error) {
	if err := models.SetSetting(r.DB, "github_repo", repo); err != nil {
		return nil, err
	}
	if err := models.SetSensitiveSetting(r.DB, "github_token", token); err != nil {
		return nil, err
	}
	return &GeneralResponse{Success: true, Message: strPtr("GitHub config updated")}, nil
}

// DeployToGitHubPages is the resolver for the deployToGitHubPages field.
func (r *mutationResolver) DeployToGitHubPages(ctx context.Context) (*GeneralResponse, error) {
	repo, err := models.GetSetting(r.DB, "github_repo")
	if err != nil {
		return nil, fmt.Errorf("github repo not configured")
	}
	token, err := models.GetSensitiveSetting(r.DB, "github_token")
	if err != nil || token == "" {
		return nil, fmt.Errorf("github token not configured or decryption failed")
	}

	parts := strings.Split(repo, "/")
	if len(parts) != 2 {
		return nil, fmt.Errorf("invalid repo format, expected user/repo")
	}

	owner, name := parts[0], parts[1]

	// 1. Export JSON data
	tmpDir, err := os.MkdirTemp("", "c404-static-*")
	if err != nil {
		return nil, err
	}
	defer os.RemoveAll(tmpDir)

	if err := r.DeployService.ExportDataToJSON(tmpDir); err != nil {
		return nil, err
	}

	// 2. Push to GitHub
	if err := r.DeployService.DeployToGitHubPages(ctx, owner, name, token, tmpDir); err != nil {
		return nil, err
	}

	return &GeneralResponse{Success: true, Message: strPtr("Deployed successfully")}, nil
}

// CreateComment is the resolver for the createComment field.
func (r *mutationResolver) CreateComment(ctx context.Context, input CreateCommentInput) (*BlogPostComment, error) {
	// 获取当前用户
	user, err := getUserFromContext(ctx, r.Resolver.DB)
	if err != nil {
		return nil, fmt.Errorf("未授权访问: %w", err)
	}

	// 转换博客文章ID
	blogPostID, err := strconv.ParseUint(input.BlogPostID, 10, 32)
	if err != nil {
		return nil, fmt.Errorf("无效的文章ID: %w", err)
	}

	// 转换父评论ID（如果提供）
	var parentID *uint
	if input.ParentID != nil {
		pid, err := strconv.ParseUint(*input.ParentID, 10, 32)
		if err != nil {
			return nil, fmt.Errorf("无效的父评论ID: %w", err)
		}
		parentIDUint := uint(pid)
		parentID = &parentIDUint
	}

	// 准备服务层输入
	serviceInput := &services.CreateCommentInput{
		Content:    input.Content,
		BlogPostID: uint(blogPostID),
		ParentID:   parentID,
	}

	// 创建评论服务实例
	commentService := services.NewCommentService(r.Resolver.DB)

	// 创建评论
	comment, err := commentService.CreateComment(serviceInput, user.ID)
	if err != nil {
		return nil, fmt.Errorf("创建评论失败: %w", err)
	}

	// 转换为GraphQL类型
	return convertToGraphQLComment(comment), nil
}

